SELECT pl.*, pt.name AS person_type_name FROM person_library pl LEFT JOIN person_type pt ON pl.person_type_id = pt.id
AND pl.person_type_id = #{personTypeId}
AND (pl.name LIKE CONCAT('%', #{keyword}, '%') OR pl.organization LIKE CONCAT('%', #{keyword}, '%') OR pl.research_direction LIKE CONCAT('%', #{keyword}, '%'))
AND pl.approval_status = 'APPROVED'
ORDER BY pl.create_time DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE person_library
person_type_id = #{personTypeId}, name = #{name}, gender = #{gender}, phone = #{phone}, email = #{email}, avatar = #{avatar}, title = #{title}, organization = #{organization}, position = #{position}, research_direction = #{researchDirection}, achievements = #{achievements}, introduction = #{introduction}, expertise_areas = #{expertiseAreas}, status = #{status}, update_time = NOW()
WHERE id = #{id}
